// === VALIDACION_ROBUSTA_XLSX v2 ===
function _validarXLSX(buf, nombreArchivo) {
  const nombre = nombreArchivo || 'archivo';
  if (!buf || buf.length === 0) {
    throw new Error(`[XLSX_VACIO] El archivo "${nombre}" llego vacio (0 bytes). Re-subir al Drive correctamente.`);
  }
  if (buf.length < 500) {
    throw new Error(`[XLSX_PEQUENO] El archivo "${nombre}" es demasiado pequeno (${buf.length} bytes). Un xlsx valido tiene minimo ~5KB. Re-subir al Drive.`);
  }
  // Magic bytes iniciales: zip empieza con PK\x03\x04 (50 4B 03 04)
  const b0 = buf[0], b1 = buf[1], b2 = buf[2], b3 = buf[3];
  const esZip = b0 === 0x50 && b1 === 0x4B && (b2 === 0x03 || b2 === 0x05) && (b3 === 0x04 || b3 === 0x06);
  if (!esZip) {
    const hex = [b0,b1,b2,b3].map(b => (b||0).toString(16).padStart(2,'0')).join(' ');
    let pista = '';
    if (b0 === 0xD0 && b1 === 0xCF) pista = ' (archivo .xls antiguo, no .xlsx)';
    else if (b0 === 0x3C) pista = ' (HTML/XML)';
    else if (b0 === 0x7B) pista = ' (JSON)';
    else if (b0 === 0xEF && b1 === 0xBB) pista = ' (texto con BOM UTF-8)';
    throw new Error(`[XLSX_FORMATO_INCORRECTO] El archivo "${nombre}" NO es un xlsx. Bytes iniciales: ${hex}${pista}. ACCION: re-subir al Drive como .xlsx.`);
  }
  // End of Central Directory marker (PK\x05\x06 = 50 4B 05 06) en los ultimos ~22-65kb del zip
  // Buscar hacia atras desde el final
  const maxSearch = Math.min(buf.length, 65557); // EOCD puede estar precedido por hasta 64K de comentario
  let eocdEncontrado = false;
  for (let i = buf.length - 22; i >= Math.max(0, buf.length - maxSearch); i--) {
    if (buf[i] === 0x50 && buf[i+1] === 0x4B && buf[i+2] === 0x05 && buf[i+3] === 0x06) {
      eocdEncontrado = true;
      break;
    }
  }
  if (!eocdEncontrado) {
    throw new Error(`[XLSX_TRUNCADO] El archivo "${nombre}" (${buf.length} bytes) es un zip pero esta TRUNCADO o CORRUPTO (falta el marcador End-of-Central-Directory). Causa probable: el archivo se subio al Drive incompleto o se daño en la descarga. ACCION: re-subir el archivo al Drive desde el sistema fuente.`);
  }
}

async function _cargarXLSXSeguro(wb, buf, nombreArchivo) {
  try {
    await wb.xlsx.load(buf);
  } catch (e) {
    const msg = String(e?.message || e);
    if (msg.includes('central directory') || msg.includes('Corrupted zip') || msg.includes('invalid signature')) {
      throw new Error(`[XLSX_CORRUPTO] El archivo "${nombreArchivo}" no se pudo abrir (${msg.slice(0, 100)}). Causa: zip corrupto. ACCION: re-subir el archivo al Drive.`);
    }
    throw e;
  }
}
