// Pestana dinamica con REGLA DE CAMBIO DE MES (4 dias de gracia, 2026-05-27):
// Durante los primeros 4 dias del mes, los datos siguen en la hoja del MES ANTERIOR
// (cierre atrasado por feriado/fin de semana). Desde el dia 5, hoja del mes actual.
const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
let _fechaTest = null;
try { const _t = $('Execute Workflow Trigger').first().json; if (_t && _t._fecha_proceso_test) _fechaTest = _t._fecha_proceso_test; } catch (e) {}
const ahora = _fechaTest ? new Date(_fechaTest + 'T12:00:00') : new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
let _mesIdx = ahora.getMonth();
let _anio = ahora.getFullYear();
if (ahora.getDate() <= 4) {
  _mesIdx -= 1;
  if (_mesIdx < 0) { _mesIdx = 11; _anio -= 1; }
}
const sheetName = meses[_mesIdx] + ' ' + _anio;

let _hojaNueva = false;
let _plantillaSheet = null;
let ws = wb.getWorksheet(sheetName);
if (!ws) {
  // La hoja del mes destino aun no existe -> se creara en 'Write' clonando la ultima hoja.
  _hojaNueva = true;
  const _plant = wb.worksheets[wb.worksheets.length - 1];
  _plantillaSheet = _plant ? _plant.name : null;
  ws = _plant; // plantilla: solo para leer headers/columnas
}
if (!ws) throw new Error('Yopago sin worksheets');

const rowCount = ws.rowCount || 0;
if (rowCount < 2) {
  throw new Error(`Archivo vacio o solo headers en pestana '${ws.name || 'desconocida'}' (rowCount=${rowCount}). Verifica que el XLSX tenga datos.`);
}

// Leer headers (siempre fila 1)
const headerRow = ws.getRow(1);
const headers = [];
const colCount = ws.columnCount || 1;
for (let c = 1; c <= colCount; c++) {
  const v = headerRow.getCell(c).value;
  headers[c - 1] = (v == null) ? '' : String(v).trim();
}

// Buscar ultima fila con datos en col A (Fecha) para saber donde APPEND.
// Si la hoja del mes es nueva (aun no existe), arranca vacia (solo headers).
let ultimaFilaConDatos = 1; // por defecto solo el header
if (!_hojaNueva) {
  ws.eachRow({ includeEmpty: false }, (row, rowNum) => {
    const v = row.getCell(1).value;
    if (v != null && String(v).trim() !== '') {
      ultimaFilaConDatos = rowNum;
    }
  });
}

// FIX FORMATO: NO devolvemos las filas existentes (no las modificamos).
