// === FIX 1B+ 2026-05-27: punto de corte = MAX fecha de TODAS las filas ===
// Robustez: si el Yopago quedara desordenado, el corte sigue siendo la fecha mas nueva.
// (Tambien soluciona el bug "Fri": Date de otro realm se detecta con toString.call.)
function _normF(s){ s=String(s==null?'':s).trim(); if(!s)return''; s=s.split(' ')[0];
  let m=s.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/);
  if(m)return `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}`;
  m=s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/);
  if(m){let d=m[1],mo=m[2],y=m[3];if(y.length===2)y='20'+y;return `${y}-${mo.padStart(2,'0')}-${d.padStart(2,'0')}`;}
  return s; }
let ultimaFechaYopago = null;
for (let _r = 2; _r <= ultimaFilaConDatos; _r++) {
  let _vf = ws.getRow(_r).getCell(1).value;
  if (_vf == null) continue;
  if (typeof _vf === 'object' && 'result' in _vf) _vf = _vf.result;
  const _isDate = (_vf instanceof Date)
    || Object.prototype.toString.call(_vf) === '[object Date]'
    || (_vf && typeof _vf.getMonth === 'function');
  const _f = _isDate ? new Date(_vf).toISOString().slice(0,10) : _normF(_vf);
  if (_f && /^\d{4}-\d{2}-\d{2}$/.test(_f)) {
    if (ultimaFechaYopago === null || _f > ultimaFechaYopago) ultimaFechaYopago = _f;
  }
}
// === FIN FIX 1B+ ===

return [{
  json: {
    sheetName: sheetName,
    headers,
    ultimaFilaConDatos,
    ultimaFechaYopago,
    headerCount: headers.length,
    _hojaNueva,
    _plantillaSheet,
