  return ''; }

const FV = '1KZt98PYd9V6w_zfSpl-fOl6F1v56Vb4t'; const FC = '12jatMOkDTNHzIwwPZOlHnWc33uoqcxwM';
const items = $input.all();
let maxValles=null, maxCredil=null;
for(let i=0;i<items.length;i++){
  const parents = items[i].json.parents || [];
  let banco = null;
  if(parents.includes(FV)) banco='Valles';
  else if(parents.includes(FC)) banco='Credil';
  try {
    const ExcelJS=require('exceljs');
    const buf=await this.helpers.getBinaryDataBuffer(i,'data');
    const wb=new ExcelJS.Workbook(); await wb.xlsx.load(buf);
    const ws=wb.worksheets[0];
    let mx=null;
    for(let r=2;r<=ws.rowCount;r++){ const f=norm(ws.getRow(r).getCell(1).value); if(/^\d{4}-\d{2}-\d{2}$/.test(f)){ if(!mx||f>mx)mx=f; } }
    if(banco==='Valles'){ if(!maxValles||(mx&&mx>maxValles))maxValles=mx; }
    else if(banco==='Credil'){ if(!maxCredil||(mx&&mx>maxCredil))maxCredil=mx; }
  } catch(e){}
}
