try { yop = $('Read Yopago mes actual').first().json; } catch(e){ yop={ultimaFechaYopago:null,_sinYopago:true}; }
const sinYopago=!!yop._sinYopago;
let maxValles=null, maxCredil=null;
try { const d=$('Read fechas descargados').first().json; maxValles=d.max_valles; maxCredil=d.max_credil; } catch(e){}

// mapa fechas en cajas
const mapa={};
for(const r of recargas){ const f=norm(r['Fecha']||r.fecha||''); if(!f)continue; if(!mapa[f])mapa[f]={fecha:f,recargas:0,valor_total:0}; mapa[f].recargas++; const v=parseFloat(String(r['Valor Recarga']!=null?r['Valor Recarga']:(r.valor||0)).replace(/[^0-9.\-]/g,''))||0; mapa[f].valor_total=Math.round((mapa[f].valor_total+v)*100)/100; }
const fechas=Object.values(mapa).sort((a,b)=>a.fecha.localeCompare(b.fecha));
const ultimaYop = yop.ultimaFechaYopago ? norm(yop.ultimaFechaYopago) : null;
const nuevas = fechas.filter(f=>!ultimaYop || f.fecha>ultimaYop).map(f=>f.fecha);
const yaProc = fechas.filter(f=>ultimaYop && f.fecha<=ultimaYop).map(f=>f.fecha);

