const hoyStr=`${ahora.getFullYear()}-${String(ahora.getMonth()+1).padStart(2,'0')}-${String(ahora.getDate()).padStart(2,'0')}`;

let resumen;
if(sinYopago){ resumen='FALTA EL ARCHIVO YOPAGO en 4_RECARGAS_YOPAGO. Subilo antes de procesar.'; }
else if(recargas.length===0){ resumen='No hay cajas (recargas) en el input. Subi las cajas Virtualsoft.'; }
else if(faltantes.length){ resumen=`Faltan resumenes descargados: ${faltantes.join(', ')}. Sin cobertura bancaria completa NO se procesa (opcion B).`; }
else if(sugeridas.length){ resumen=`Fechas a procesar (con cobertura completa): ${sugeridas.join(', ')}.` + (pospuestas.length?` POSPUESTAS por falta de cobertura (corte ${corte}): ${pospuestas.join(', ')}.`:''); }
else if(pospuestas.length){ resumen=`Todas las fechas nuevas (${pospuestas.join(', ')}) superan el corte comun ${corte} (algun banco no las cubre aun). No se procesa ninguna hasta tener los archivos.`; }
else { resumen=`No hay fechas nuevas. Ultima en Yopago: ${ultimaYop||'?'}.`; }

return [{ json: {
  ok: !sinYopago && faltantes.length===0,
  falta_yopago: sinYopago,
  faltan_descargados: faltantes,
  hay_cajas: recargas.length>0,
  dia_actual: hoyStr,
  ultima_fecha_yopago: ultimaYop,
  corte_comun: corte,
  max_resumen_valles: maxValles,
  max_resumen_credil: maxCredil,
  total_recargas_en_cajas: recargas.length,
  fechas_en_cajas: fechas,
  fechas_sugeridas: sugeridas,
  fechas_pospuestas: pospuestas,
  fechas_ya_procesadas: yaProc,
  resumen,
}}];
